const { db } = require('../config/database');

class Achievement {
  constructor(data) {
    this.id = data.id;
    this.name = data.name;
    this.description = data.description;
    this.category = data.category;
    this.type = data.type;
    this.requirement = data.requirement;
    this.reward_points = data.reward_points;
    this.reward_items = typeof data.reward_items === 'string' 
      ? JSON.parse(data.reward_items) 
      : data.reward_items;
    this.icon_url = data.icon_url;
    this.is_active = data.is_active;
    this.created_at = data.created_at;
    this.updated_at = data.updated_at;
  }

  // 创建成就
  static async create(achievementData) {
    const [achievement] = await db('achievements')
      .insert({
        name: achievementData.name,
        description: achievementData.description,
        category: achievementData.category,
        type: achievementData.type,
        requirement: achievementData.requirement,
        reward_points: achievementData.reward_points || 0,
        reward_items: JSON.stringify(achievementData.reward_items || []),
        icon_url: achievementData.icon_url,
        is_active: true
      })
      .returning('*');
    
    return new Achievement(achievement);
  }

  // 获取所有成就
  static async getAllAchievements() {
    const achievements = await db('achievements')
      .where('is_active', true)
      .orderBy('category', 'asc')
      .orderBy('requirement', 'asc');
    
    return achievements.map(achievement => new Achievement(achievement));
  }

  // 根据分类获取成就
  static async getAchievementsByCategory(category) {
    const achievements = await db('achievements')
      .where('category', category)
      .where('is_active', true)
      .orderBy('requirement', 'asc');
    
    return achievements.map(achievement => new Achievement(achievement));
  }

  // 获取用户成就
  static async getUserAchievements(userId) {
    const userAchievements = await db('user_achievements as ua')
      .join('achievements as a', 'ua.achievement_id', 'a.id')
      .where('ua.user_id', userId)
      .where('a.is_active', true)
      .select(
        'ua.*',
        'a.name',
        'a.description',
        'a.category',
        'a.type',
        'a.requirement',
        'a.reward_points',
        'a.reward_items',
        'a.icon_url'
      )
      .orderBy('a.category', 'asc')
      .orderBy('a.requirement', 'asc');
    
    return userAchievements.map(ua => ({
      id: ua.id,
      user_id: ua.user_id,
      achievement_id: ua.achievement_id,
      progress: ua.progress,
      is_completed: ua.is_completed,
      completed_at: ua.completed_at,
      is_claimed: ua.is_claimed,
      claimed_at: ua.claimed_at,
      created_at: ua.created_at,
      updated_at: ua.updated_at,
      achievement: new Achievement({
        id: ua.achievement_id,
        name: ua.name,
        description: ua.description,
        category: ua.category,
        type: ua.type,
        requirement: ua.requirement,
        reward_points: ua.reward_points,
        reward_items: ua.reward_items,
        icon_url: ua.icon_url,
        is_active: true,
        created_at: ua.created_at,
        updated_at: ua.updated_at
      })
    }));
  }

  // 获取用户已完成的成就
  static async getUserCompletedAchievements(userId) {
    const userAchievements = await db('user_achievements as ua')
      .join('achievements as a', 'ua.achievement_id', 'a.id')
      .where('ua.user_id', userId)
      .where('ua.is_completed', true)
      .where('a.is_active', true)
      .select(
        'ua.*',
        'a.name',
        'a.description',
        'a.category',
        'a.type',
        'a.requirement',
        'a.reward_points',
        'a.reward_items',
        'a.icon_url'
      )
      .orderBy('ua.completed_at', 'desc');
    
    return userAchievements.map(ua => ({
      id: ua.id,
      user_id: ua.user_id,
      achievement_id: ua.achievement_id,
      progress: ua.progress,
      is_completed: ua.is_completed,
      completed_at: ua.completed_at,
      is_claimed: ua.is_claimed,
      claimed_at: ua.claimed_at,
      created_at: ua.created_at,
      updated_at: ua.updated_at,
      achievement: new Achievement({
        id: ua.achievement_id,
        name: ua.name,
        description: ua.description,
        category: ua.category,
        type: ua.type,
        requirement: ua.requirement,
        reward_points: ua.reward_points,
        reward_items: ua.reward_items,
        icon_url: ua.icon_url,
        is_active: true,
        created_at: ua.created_at,
        updated_at: ua.updated_at
      })
    }));
  }

  // 初始化用户成就
  static async initializeUserAchievements(userId) {
    const achievements = await this.getAllAchievements();
    
    for (const achievement of achievements) {
      await db('user_achievements').insert({
        user_id: userId,
        achievement_id: achievement.id,
        progress: 0,
        is_completed: false,
        is_claimed: false
      });
    }
  }

  // 更新用户成就进度
  static async updateUserAchievementProgress(userId, achievementId, progress) {
    const userAchievement = await db('user_achievements')
      .where('user_id', userId)
      .where('achievement_id', achievementId)
      .first();

    if (!userAchievement) {
      throw new Error('用户成就不存在');
    }

    const achievement = await db('achievements')
      .where('id', achievementId)
      .first();

    if (!achievement) {
      throw new Error('成就不存在');
    }

    const isCompleted = progress >= achievement.requirement && !userAchievement.is_completed;

    await db('user_achievements')
      .where('user_id', userId)
      .where('achievement_id', achievementId)
      .update({
        progress: Math.max(progress, userAchievement.progress),
        is_completed: isCompleted || userAchievement.is_completed,
        completed_at: isCompleted ? db.fn.now() : userAchievement.completed_at,
        updated_at: db.fn.now()
      });

    return { isCompleted, progress: Math.max(progress, userAchievement.progress) };
  }

  // 领取成就奖励
  static async claimAchievementReward(userId, achievementId) {
    const userAchievement = await db('user_achievements')
      .where('user_id', userId)
      .where('achievement_id', achievementId)
      .first();

    if (!userAchievement) {
      throw new Error('用户成就不存在');
    }

    if (!userAchievement.is_completed) {
      throw new Error('成就未完成');
    }

    if (userAchievement.is_claimed) {
      throw new Error('奖励已领取');
    }

    const achievement = await db('achievements')
      .where('id', achievementId)
      .first();

    if (!achievement) {
      throw new Error('成就不存在');
    }

    // 开始事务
    await db.transaction(async (trx) => {
      // 更新用户积分
      if (achievement.reward_points > 0) {
        await trx('users')
          .where('id', userId)
          .increment('points', achievement.reward_points);
      }

      // 添加奖励道具到用户库存
      if (achievement.reward_items && achievement.reward_items.length > 0) {
        for (const itemId of achievement.reward_items) {
          const existingInventory = await trx('user_inventory')
            .where('user_id', userId)
            .where('item_id', itemId)
            .first();

          if (existingInventory) {
            await trx('user_inventory')
              .where('user_id', userId)
              .where('item_id', itemId)
              .increment('quantity', 1);
          } else {
            await trx('user_inventory').insert({
              user_id: userId,
              item_id: itemId,
              quantity: 1
            });
          }
        }
      }

      // 标记奖励已领取
      await trx('user_achievements')
        .where('user_id', userId)
        .where('achievement_id', achievementId)
        .update({
          is_claimed: true,
          claimed_at: trx.fn.now(),
          updated_at: trx.fn.now()
        });
    });

    return {
      reward_points: achievement.reward_points,
      reward_items: achievement.reward_items
    };
  }

  // 获取用户成就统计
  static async getUserAchievementStats(userId) {
    const stats = await db('user_achievements as ua')
      .join('achievements as a', 'ua.achievement_id', 'a.id')
      .where('ua.user_id', userId)
      .where('a.is_active', true)
      .select(
        db.raw('COUNT(*) as total_achievements'),
        db.raw('SUM(CASE WHEN ua.is_completed = true THEN 1 ELSE 0 END) as completed_achievements'),
        db.raw('SUM(CASE WHEN ua.is_claimed = true THEN 1 ELSE 0 END) as claimed_achievements'),
        db.raw('SUM(CASE WHEN ua.is_completed = true THEN a.reward_points ELSE 0 END) as total_reward_points')
      )
      .first();

    return {
      total_achievements: parseInt(stats.total_achievements) || 0,
      completed_achievements: parseInt(stats.completed_achievements) || 0,
      claimed_achievements: parseInt(stats.claimed_achievements) || 0,
      total_reward_points: parseInt(stats.total_reward_points) || 0,
      completion_rate: stats.total_achievements > 0 
        ? Math.round((stats.completed_achievements / stats.total_achievements) * 100) 
        : 0
    };
  }
}

module.exports = Achievement;
